//! SystemVerilog emission (parity with VHDL + Rust) for Yosys / SymbiYosys.

pub fn emit_resolution_lift_sv() -> String {
    r#"// Generated by gnosis-rtl-bridge; parity with distributed_inference::attention_closure_lift
module gnosis_resolution_lift_fsm_v0 (
    input  wire [3:0]  i_heads,
    input  wire [15:0] i_coupling,
    input  wire [15:0] i_observer_resolution,
    input  wire [15:0] i_residue_threshold,
    output logic       o_lift,
    output logic [15:0] o_after_observer_resolution
);
  localparam int TRITON_PHASE = 3;

  function automatic int unsigned head_phase(input int unsigned head);
    return TRITON_PHASE * (head + 1);
  endfunction

  function automatic int unsigned coord_at_res(
    input int unsigned head,
    input int unsigned res
  );
    int unsigned denom;
    denom = (res < 1) ? 1 : res;
    return head_phase(head) % denom;
  endfunction

  function automatic bit trace_sep8(
    input int unsigned t0, t1, t2, t3, t4, t5, t6, t7,
    input int unsigned heads
  );
    int unsigned tr[8];
    tr[0] = t0; tr[1] = t1; tr[2] = t2; tr[3] = t3;
    tr[4] = t4; tr[5] = t5; tr[6] = t6; tr[7] = t7;
    for (int ii = 0; ii < int'(heads); ii++) begin
      for (int jj = ii + 1; jj < int'(heads); jj++) begin
        if (tr[ii] == tr[jj]) return 1'b0;
      end
    end
    return 1'b1;
  endfunction

  always_comb begin
    int unsigned heads_v, coupling_v, obs_v, thr_v;
    int unsigned obs_eff, multi_head, source_res, unresolved;
    int unsigned t0, t1, t2, t3, t4, t5, t6, t7;
    bit sep, should_lift;
    int unsigned after_obs;

    heads_v = (i_heads > 8) ? 8 : i_heads;
    coupling_v = i_coupling;
    obs_v = i_observer_resolution;
    thr_v = i_residue_threshold;

    obs_eff = (obs_v < 1) ? 1 : obs_v;
    multi_head = TRITON_PHASE * heads_v;
    source_res = multi_head + coupling_v;
    unresolved = (source_res >= obs_eff) ? (source_res - obs_eff) : 0;

    t0 = coord_at_res(0, obs_eff);
    t1 = coord_at_res(1, obs_eff);
    t2 = coord_at_res(2, obs_eff);
    t3 = coord_at_res(3, obs_eff);
    t4 = coord_at_res(4, obs_eff);
    t5 = coord_at_res(5, obs_eff);
    t6 = coord_at_res(6, obs_eff);
    t7 = coord_at_res(7, obs_eff);

    sep = (heads_v < 1) ? 1'b1 : trace_sep8(t0, t1, t2, t3, t4, t5, t6, t7, heads_v);

    if (thr_v < 1)
      should_lift = (!sep) || (unresolved >= 1);
    else
      should_lift = (!sep) || (unresolved >= thr_v);

    if (should_lift) begin
      o_lift = 1'b1;
      after_obs = source_res;
    end else begin
      o_lift = 1'b0;
      after_obs = obs_v;
    end

    o_after_observer_resolution = (after_obs > 65535) ? 16'hFFFF : after_obs[15:0];
  end
endmodule
"#
    .to_string()
}
